 29 /// StackOffset holds a fixed and a scalable offset in bytes.
 30 class StackOffset {
 31   int64_t Fixed = 0;
 32   int64_t Scalable = 0;
 33 
 34   StackOffset(int64_t Fixed, int64_t Scalable)
 35       : Fixed(Fixed), Scalable(Scalable) {}
 36 
