473       return ReadDataFromGlobal(C, ByteOffset, CurPtr, BytesLeft, DL);
474     }
475     return false;
476   }
477 
478   if (auto *CS = dyn_cast<ConstantStruct>(C)) {
479     const StructLayout *SL = DL.getStructLayout(CS->getType());
480     unsigned Index = SL->getElementContainingOffset(ByteOffset);
481     uint64_t CurEltOffset = SL->getElementOffset(Index);
482     ByteOffset -= CurEltOffset;
483 
484     while (true) {
485       // If the element access is to the element itself and not to tail padding,
486       // read the bytes from the element.
487       uint64_t EltSize = DL.getTypeAllocSize(CS->getOperand(Index)->getType());
488 
489       if (ByteOffset < EltSize &&
490           !ReadDataFromGlobal(CS->getOperand(Index), ByteOffset, CurPtr,
491                               BytesLeft, DL))
492         return false;
493 
494       ++Index;
495 
496       // Check to see if we read from the last struct element, if so we're done.
497       if (Index == CS->getType()->getNumElements())
498         return true;
499 
500       // If we read all of the bytes we needed from this element we're done.
501       uint64_t NextEltOffset = SL->getElementOffset(Index);
502 
503       if (BytesLeft <= NextEltOffset - CurEltOffset - ByteOffset)
504         return true;
505 
506       // Move to the next element of the struct.
507       CurPtr += NextEltOffset - CurEltOffset - ByteOffset;
508       BytesLeft -= NextEltOffset - CurEltOffset - ByteOffset;
509       ByteOffset = 0;
510       CurEltOffset = NextEltOffset;
511     }
512     // not reached.
513   }
514 
515   if (isa<ConstantArray>(C) || isa<ConstantVector>(C) ||
516       isa<ConstantDataSequential>(C) || isa<ConstantInt>(C) ||
517       isa<ConstantFP>(C)) {
518     uint64_t NumElts, EltSize;
519     Type *EltTy;
520     if (auto *AT = dyn_cast<ArrayType>(C->getType())) {
521       NumElts = AT->getNumElements();
522       EltTy = AT->getElementType();
523       EltSize = DL.getTypeAllocSize(EltTy);
524     } else {
525       NumElts = cast<FixedVectorType>(C->getType())->getNumElements();
526       EltTy = cast<FixedVectorType>(C->getType())->getElementType();
527       // TODO: For non-byte-sized vectors, current implementation assumes there is
528       // padding to the next byte boundary between elements.
529       if (!DL.typeSizeEqualsStoreSize(EltTy))
530         return false;
531 
532       EltSize = DL.getTypeStoreSize(EltTy);
533     }
534     uint64_t Index = ByteOffset / EltSize;
535     uint64_t Offset = ByteOffset - Index * EltSize;
536 
537     for (; Index != NumElts; ++Index) {
538       if (!ReadDataFromGlobal(C->getAggregateElement(Index), Offset, CurPtr,
539                               BytesLeft, DL))
540         return false;
541 
542       uint64_t BytesWritten = EltSize - Offset;
543       assert(BytesWritten <= EltSize && "Not indexing into this element?");
544       if (BytesWritten >= BytesLeft)
545         return true;
546 
547       Offset = 0;
548       BytesLeft -= BytesWritten;
549       CurPtr += BytesWritten;
550     }
551     return true;
552   }
553 
554   if (auto *CE = dyn_cast<ConstantExpr>(C)) {
555     if (CE->getOpcode() == Instruction::IntToPtr &&
556         CE->getOperand(0)->getType() == DL.getIntPtrType(CE->getType())) {
557       return ReadDataFromGlobal(CE->getOperand(0), ByteOffset, CurPtr,
558                                 BytesLeft, DL);
559     }
560   }
561 
562   // Otherwise, unknown initializer type.
563   return false;
564 }
